import{_ as e,c as t,o,a1 as n}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"快速開始: 上手 Plannotator | plannotator","description":"學習 Plannotator 的快速開始方法。在 5 分鐘內瞭解核心功能，完成 Claude Code 或 OpenCode 外掛安裝設定。","frontmatter":{"title":"快速開始: 上手 Plannotator | plannotator","sidebarTitle":"5 分鐘快速上手","subtitle":"快速開始: 上手 Plannotator","description":"學習 Plannotator 的快速開始方法。在 5 分鐘內瞭解核心功能，完成 Claude Code 或 OpenCode 外掛安裝設定。","order":1},"headers":[],"relativePath":"zh-tw/backnotprop/plannotator/start/index.md","filePath":"zh-tw/backnotprop/plannotator/start/index.md"}'),l={name:"zh-tw/backnotprop/plannotator/start/index.md"};function r(d,a,i,s,c,p){return o(),t("div",null,[...a[0]||(a[0]=[n('<h1 id="快速開始" tabindex="-1">快速開始 <a class="header-anchor" href="#快速開始" aria-label="Permalink to &quot;快速開始&quot;">​</a></h1><p>本章節幫助你從零開始使用 Plannotator。你將瞭解 Plannotator 是什麼、它能解決什麼問題，並在你使用的 AI Coding Agent（Claude Code 或 OpenCode）中完成安裝設定。</p><h2 id="本章內容" tabindex="-1">本章內容 <a class="header-anchor" href="#本章內容" aria-label="Permalink to &quot;本章內容&quot;">​</a></h2><div class="grid-cards"><h3 id="快速開始-1" tabindex="-1"><a href="./getting-started/">快速開始</a> <a class="header-anchor" href="#快速開始-1" aria-label="Permalink to &quot;[快速開始](./getting-started/)&quot;">​</a></h3><p>瞭解 Plannotator 的核心功能和使用情境，在 5 分鐘內完成首次體驗。適合所有新使用者作為入門第一課。</p><h3 id="安裝-claude-code-外掛" tabindex="-1"><a href="./installation-claude-code/">安裝 Claude Code 外掛</a> <a class="header-anchor" href="#安裝-claude-code-外掛" aria-label="Permalink to &quot;[安裝 Claude Code 外掛](./installation-claude-code/)&quot;">​</a></h3><p>在 Claude Code 中安裝並設定 Plannotator 外掛，支援外掛系統和手動 Hook 兩種方式，涵蓋本機和遠端環境設定。</p><h3 id="安裝-opencode-外掛" tabindex="-1"><a href="./installation-opencode/">安裝 OpenCode 外掛</a> <a class="header-anchor" href="#安裝-opencode-外掛" aria-label="Permalink to &quot;[安裝 OpenCode 外掛](./installation-opencode/)&quot;">​</a></h3><p>在 OpenCode 中安裝並設定 Plannotator 外掛，啟用 <code>submit_plan</code> tool 和 <code>/plannotator-review</code> 指令。</p></div><h2 id="學習路徑" tabindex="-1">學習路徑 <a class="header-anchor" href="#學習路徑" aria-label="Permalink to &quot;學習路徑&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">建議順序</p><ol><li><strong>先讀 <a href="./getting-started/">快速開始</a></strong>：瞭解 Plannotator 是什麼、能做什麼，建立整體認知</li><li><strong>再選一個安裝教學</strong>：根據你使用的 AI Coding Agent 選擇對應的安裝指南 <ul><li>使用 Claude Code → <a href="./installation-claude-code/">安裝 Claude Code 外掛</a></li><li>使用 OpenCode → <a href="./installation-opencode/">安裝 OpenCode 外掛</a></li></ul></li></ol></div><p>完成安裝後，你就可以開始使用 Plannotator 進行計畫審查和程式碼審查了。</p><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><p>完成本章節後，繼續學習 <strong><a href="./../platforms/">平台功能</a></strong>，掌握計畫審查和程式碼審查的完整用法：</p><ul><li>計畫審查基礎：批准、拒絕、新增註解</li><li>圖像標註：在計畫中附加截圖並標註</li><li>程式碼審查：視覺化 Git diff，新增行級註解</li></ul>',10)])])}const C=e(l,[["render",r]]);export{u as __pageData,C as default};
